 17	import { CheckCircleIcon } from '@patternfly/react-icons';
 18	import * as React from 'react';
 19	import { useTranslation } from 'react-i18next';
 20	import { HealthCard } from './health-card';
 21	import { HealthStat, HealthSuperKind } from './health-helper';
 22	import { RuleDetails } from './rule-details';
 23	
 24	export interface HealthDrawerContainerProps {
 25	  title: string;
 26	  stats: HealthStat[];
 27	  kind: HealthSuperKind;
 28	  isDark: boolean;
 29	}
 30	
 31	export const HealthDrawerContainer: React.FC<HealthDrawerContainerProps> = ({ title, stats, kind, isDark }) => {
 32	  const { t } = useTranslation('plugin__netobserv-plugin');
 33	  const [selectedItemName, setSelectedItemName] = React.useState<string | undefined>(undefined);
 34	  const drawerRef = React.useRef<HTMLDivElement>(null);
 35	
 36	  const onExpand = () => {
 37	    if (drawerRef.current) {
 38	      drawerRef.current.focus();
 39	    }
 40	  };
 41	
 42	  const selectedItem = React.useMemo(() => {
 43	    return selectedItemName ? stats.find(item => item.name === selectedItemName) : undefined;
 44	  }, [selectedItemName, stats]);
 45	
 46	  const isExpanded = selectedItem !== undefined;
 47	  const hasAnyViolations = stats.length > 0;
 48	
 49	  return (
 50	    <>
 51	      <Drawer isExpanded={isExpanded} onExpand={onExpand} isInline>
 52	        <DrawerContent
 53	          panelContent={
 54	            <DrawerPanelContent
 55	              className={'health-gallery-drawer'}
 56	              isResizable
 57	              widths={{ default: 'width_33' }}
 58	              minSize="300px"
 59	            >
 60	              <DrawerHead>
 61	                <span tabIndex={isExpanded ? 0 : -1} ref={drawerRef}>
 62	                  {selectedItem && <ResourceLink inline={true} kind={selectedItem.k8sKind} name={selectedItem.name} />}
 63	                </span>
 64	              </DrawerHead>
 65	              {selectedItem && (
 66	                <div className="health-gallery-drawer-content">
 67	                  <RuleDetails kind={kind} resourceHealth={selectedItem} />
 68	                </div>
 69	              )}
 70	            </DrawerPanelContent>
 71	          }
 72	        >
 73	          <DrawerContentBody>
 74	            <TextContent>
 75	              <Text component={TextVariants.h3}>{title}</Text>
 76	            </TextContent>
 77	            {!hasAnyViolations && (
 78	              <Bullseye>
 79	                <EmptyState>
 80	                  <EmptyStateHeader
 81	                    titleText={t('No violations found')}
 82	                    headingLevel="h2"
 83	                    icon={<EmptyStateIcon icon={CheckCircleIcon} />}
 84	                  />
 85	                </EmptyState>
 86	              </Bullseye>
 87	            )}
 88	            {hasAnyViolations && (
 89	              <Gallery hasGutter minWidths={{ default: '300px' }} style={{ marginRight: '1.5rem' }}>
 90	                {stats.map(item => (
 91	                  <HealthCard
 92	                    key={`card-${item.name}`}
 93	                    name={item.name}
 94	                    k8sKind={item.k8sKind}
 95	                    isDark={isDark}
 96	                    resourceHealth={item}
 97	                    isSelected={item.name === selectedItemName}
 98	                    onClick={() => {
 99	                      setSelectedItemName(item.name !== selectedItemName ? item.name : undefined);
100	                    }}
101	                  />
102	                ))}
103	              </Gallery>
104	            )}
105	          </DrawerContentBody>
106	        </DrawerContent>
107	      </Drawer>
108	    </>
109	  );
110	};

